   756→void ConnectionManagerImpl::onIdleTimeout() {
   757→  ENVOY_CONN_LOG(debug, "idle timeout", read_callbacks_->connection());
   758→  stats_.named_.downstream_cx_idle_timeout_.inc();
   759→  if (!codec_) {
   760→    // No need to delay close after flushing since an idle timeout has already fired. Attempt to
   761→    // write out buffered data one last time and issue a local close if successful.
   762→    doConnectionClose(Network::ConnectionCloseType::FlushWrite, absl::nullopt,
   763→                      StreamInfo::LocalCloseReasons::get().IdleTimeoutOnConnection);
   764→  } else if (drain_state_ == DrainState::NotDraining) {
   765→    startDrainSequence();
   766→  }
   767→}
