  2349→  }
  2350→  const Router::RouteEntry* route_entry = cached_route_.value()->routeEntry();
  2351→  if (route_entry == nullptr) {
  2352→    return;
  2353→  }
  2354→
  2355→  if (route_entry->idleTimeout().has_value()) {
  2356→    idle_timeout_ms_ = route_entry->idleTimeout().value();
  2357→    if (idle_timeout_ms_.count()) {
  2358→      // If we have a route-level idle timeout but no global stream idle timeout, create a timer.
  2359→      if (stream_idle_timer_ == nullptr) {
  2360→        stream_idle_timer_ = connection_manager_.dispatcher_->createScaledTimer(
  2361→            Event::ScaledTimerType::HttpDownstreamIdleStreamTimeout,
  2362→            [this]() -> void { onIdleTimeout(); });
  2363→      }
  2364→    } else if (stream_idle_timer_ != nullptr) {
  2365→      // If we had a global stream idle timeout but the route-level idle timeout is set to zero
  2366→      // (to override), we disable the idle timer.
  2367→      stream_idle_timer_->disableTimer();
  2368→      stream_idle_timer_ = nullptr;
  2369→    }
  2370→  }
  2371→
  2372→  if (route_entry->flushTimeout().has_value()) {
  2373→    response_encoder_->getStream().setFlushTimeout(route_entry->flushTimeout().value());
  2374→  } else if (!has_explicit_global_flush_timeout_ && route_entry->idleTimeout().has_value()) {
  2375→    // If there is no route-level flush timeout, and the global flush timeout was also inherited
  2376→    // from the idle timeout, also inherit the route-level idle timeout. This is for backwards
  2377→    // compatibility.
  2378→    response_encoder_->getStream().setFlushTimeout(idle_timeout_ms_);
